        storageGib: 15,
        numVirtualCpus: 4,
    },
    regions: [{
        name: "us-central1",
        nodeCount: 1,
    }],
    deleteProtection: true,
    backupConfig: {
        enabled: true,
        frequencyMinutes: 60,
        retentionDays: 30,
    },
    labels: {
        environment: "production",
        "cost-center": "mkt-1234",
    },
});
