        },
        upgradeType: "AUTOMATIC",
    },
    regions: [{
        name: "us-east1",
    }],
    deleteProtection: false,
    backupConfig: {
        enabled: true,
        frequencyMinutes: 60,
        retentionDays: 30,
    },
    labels: {
        environment: "production",
        "cost-center": "hr-1234",
    },
});
