import * as pulumi from "@pulumi/pulumi";
import * as cockroach from "@nellisauction/pulumi-cockroach";
import * as confluent from "@pulumi/confluent";

const myCluster = new cockroach.Cluster("my_cluster", {
    name: "my-cluster",
    cloudProvider: "AWS",
    plan: "ADVANCED",
    dedicated: {
        storageGib: 15,
        numVirtualCpus: 4,
    },
    regions: [{
        name: "us-east-1",
        nodeCount: 1,
    }],
});
const basicEgressPrivateEndpoint = new cockroach.EgressPrivateEndpoint("basic", {
    clusterId: myCluster.id,
    region: "us-east-1",
    targetServiceType: "PRIVATE_SERVICE",
    targetServiceIdentifier: "com.amazonaws.vpce.us-east-1.vpce-svc-01234567890abcdef",
});
// Example: Basic usage with custom domain names
const basic = new cockroach.EgressPrivateEndpointDomainNames("basic", {
    clusterId: myCluster.id,
    endpointId: basicEgressPrivateEndpoint.id,
    domainNames: [
        "*.custom.domain",
        "another.domain",
    ],
});
const main = new confluent.index.Environment("main", {displayName: "main"});
const mainPrivateLinkAttachment = new confluent.index.PrivateLinkAttachment("main", {
    cloud: "AWS",
    region: "us-east-1",
    displayName: "main-private-link-attachment",
    environment: [{
        id: main.id,
    }],
});
const confluentCloudEgressPrivateEndpoint = new cockroach.EgressPrivateEndpoint("confluent_cloud", {
    clusterId: myCluster.id,
    region: "us-east-1",
    targetServiceType: "PRIVATE_SERVICE",
    targetServiceIdentifier: mainPrivateLinkAttachment.aws.vpcEndpointServiceName,
});
const cockroachCloud = new confluent.index.PrivateLinkAttachmentConnection("cockroach_cloud", {
    displayName: "cockroach-cloud-access-point",
    environment: [{
        id: main.id,
    }],
    aws: [{
        vpcEndpointId: confluentCloudEgressPrivateEndpoint.endpointConnectionId,
    }],
    privateLinkAttachment: [{
        id: mainPrivateLinkAttachment.id,
    }],
});
// Example: Usage when connecting to Confluent Cloud
const confluentCloud = new cockroach.EgressPrivateEndpointDomainNames("confluent_cloud", {
    clusterId: myCluster.id,
    endpointId: confluentCloudEgressPrivateEndpoint.id,
    domainNames: ["*.us-east-1.aws.private.confluent.cloud"],
}, {
    dependsOn: [cockroachCloud],
});
export const confluentCloudEgressPrivateEndpointDomains = {
    endpointId: confluentCloud.endpointId,
    clusterId: confluentCloud.clusterId,
    domainNames: confluentCloud.domainNames,
};
